import { test, expect } from '@playwright/test';
import fs from 'node:fs';
import path from 'node:path';

const fixtureServerUrl = 'http://127.0.0.1:3001';

// The real-hls.js fixture is generated by scripts/gen-hls-fixture.sh (ffmpeg).
// If it is absent (e.g. ffmpeg not installed), skip rather than fail with a
// confusing 404/timeout — the boot smoke still proves the harness works.
const hlsFixture = path.resolve(__dirname, '../fixtures/hls/index.m3u8');

/**
 * Real-hls.js playback smoke. Unlike the jsdom unit tests (which mock the HLS
 * runtime entirely), this drives an actual Chromium + real hls.js against a
 * real HLS fixture served by the fixture-server. It proves the one thing the
 * unit tests cannot: frames actually advance.
 *
 * Covers the Windows/Linux/Android = hls.js path of the browser matrix.
 * The Safari/native-HLS path is NOT covered here (no WebKit installed; Linux
 * WebKit has no native HLS anyway).
 *
 * The playback-live scenario's backend contract (POST /live/stream-info ->
 * POST /intents (202) -> GET /sessions/{id} -> heartbeat) is verified against
 * usePlaybackOrchestrator.ts, useLiveSessionController.ts and the generated
 * client types as of 2026-05-24. The UI selectors below (route, Watch button,
 * video element) are confirmed against the source. On the first lab run, still
 * watch the fixture-server log for any /api/v3/* path returning 404 ("Mock path
 * not defined") in case a contract field drifts.
 */
test.describe('WebUI live playback (real hls.js)', () => {
  test.beforeEach(async ({ request }) => {
    test.skip(!fs.existsSync(hlsFixture), 'HLS fixture missing — run backend/e2e/scripts/gen-hls-fixture.sh (needs ffmpeg)');
    const response = await request.post(`${fixtureServerUrl}/__admin/scenario`, {
      data: { id: 'playback-live' },
    });
    expect(response.ok()).toBeTruthy();
  });

  test('starts a live channel and advances video frames', async ({ page }) => {
    await page.goto('/epg');

    // Start playback for the only channel in the scenario (Das Erste HD).
    // The play CTA renders as a button labelled "Watch" under en-US locale.
    await page.getByRole('button', { name: /watch/i }).first().click();

    // V3Player mounts lazily and renders a <video> element.
    const video = page.locator('video');
    await expect(video).toBeVisible({ timeout: 15_000 });

    // Mute + play defensively: the click is a user gesture, but hls.js attaches
    // asynchronously, so kick playback explicitly to avoid autoplay flake.
    await video.evaluate((el: HTMLVideoElement) => {
      el.muted = true;
      return el.play().catch(() => undefined);
    });

    // The actual assertion: currentTime must advance (frames are decoding).
    await expect
      .poll(
        async () => video.evaluate((el: HTMLVideoElement) => el.currentTime),
        { timeout: 15_000, message: 'video.currentTime did not advance — playback did not start' },
      )
      .toBeGreaterThan(0.2);

    // No fatal media error surfaced (hls.js fatal errors set readyState back
    // and the player shows an error surface). Sanity-check the element is live.
    const errored = await video.evaluate((el: HTMLVideoElement) => el.error?.code ?? null);
    expect(errored).toBeNull();
  });
});

/**
 * Capacity-rejection (no free tuner) error path. The orchestrator's value is in
 * how it FAILS, not only how it succeeds: R_LEASE_BUSY is the most common live
 * failure a user actually hits. This needs no HLS fixture — playback never
 * reaches hls.js — so it runs even without ffmpeg.
 *
 * The error surfaces at the GET /sessions/{id} poll (state=FAILED + R_LEASE_BUSY),
 * not at the intent, so stream.start is identical to the happy path.
 */
test.describe('WebUI live playback errors', () => {
  // Serial mode: each test mutates the fixture server's global activeScenario
  // via POST /__admin/scenario. Parallel workers would overwrite each other's
  // scenario, causing nondeterministic cross-scenario flakes.
  test.describe.configure({ mode: 'serial' });
  async function startPlaybackUnder(page: import('@playwright/test').Page, request: import('@playwright/test').APIRequestContext, scenarioId: string) {
    const response = await request.post(`${fixtureServerUrl}/__admin/scenario`, { data: { id: scenarioId } });
    expect(response.ok()).toBeTruthy();
    await page.goto('/epg');
    await page.getByRole('button', { name: /watch/i }).first().click();
  }

  // Each surface asserts the en-US locale string the player renders for that
  // failure (src/locales/en.json), so a wording/contract change is caught.
  test('capacity rejected (R_LEASE_BUSY) → "all tuners in use" surface', async ({ page, request }) => {
    await startPlaybackUnder(page, request, 'playback-lease-busy');
    await expect(page.getByText(/all tuners are currently in use/i)).toBeVisible({ timeout: 15_000 });
  });

  test('auth denied (HTTP 403) → "access denied" surface', async ({ page, request }) => {
    await startPlaybackUnder(page, request, 'playback-forbidden');
    await expect(page.getByText(/access denied/i)).toBeVisible({ timeout: 15_000 });
  });

  test('policy denied (mode=deny) → "playback denied" surface', async ({ page, request }) => {
    await startPlaybackUnder(page, request, 'playback-denied');
    await expect(page.getByText(/playback denied/i)).toBeVisible({ timeout: 15_000 });
  });

  // Fires the intent-boundary guard: a 202 with no sessionId must surface an
  // error, not poison the session poll with a null id. This is the load test
  // for the guard added alongside this spec — proving it actually catches a
  // malformed contract, not just that the happy path passes a valid one.
  test('malformed intent (202 without sessionId) → "session failed" surface', async ({ page, request }) => {
    await startPlaybackUnder(page, request, 'playback-bad-intent');
    await expect(page.getByText(/session failed/i)).toBeVisible({ timeout: 15_000 });
  });
});
